module RefModule(CLK, RST, Q);
input CLK, RST;
output [2:0] Q;
reg [2:0] Q;
reg [2:0] unused_binary_counter;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        unused_binary_counter <= 0;
        Q <= 0;
    end else begin
        unused_binary_counter <= unused_binary_counter + 1;
        Q <= (unused_binary_counter >> 1) ^ unused_binary_counter; // Convert binary to gray code
    end
end

endmodule
